mapper.select:
SELECT l.*, CASE WHEN l.user_type = 1 THEN (SELECT real_name FROM admin WHERE admin_id = l.user_id) WHEN l.user_type = 2 THEN (SELECT real_name FROM teacher WHERE teacher_id = l.user_id) WHEN l.user_type = 3 THEN (SELECT real_name FROM student WHERE student_id = l.user_id) END AS user_name FROM system_log l
AND l.user_type = #{userType}
AND l.operation LIKE CONCAT('%', #{operation}, '%')
AND DATE(l.create_time) >= #{startDate}
AND DATE(l.create_time) <= #{endDate}
ORDER BY l.create_time DESC
